cisco_ebgp_peer.config:
router bgp {LOCAL_AS}
  bgp router-id {LOOPBACK_IP}
  bgp log-neighbor-changes
  no auto-summary
  !
  neighbor {PEER_IP} remote-as {PEER_AS}
  neighbor {PEER_IP} description {PEER_DESCRIPTION}
  neighbor {PEER_IP} password 7 {ENCRYPTED_PASSWORD}
  neighbor {PEER_IP} update-source Loopback0
  neighbor {PEER_IP} ebgp-multihop 2
  neighbor {PEER_IP} timers 5 15
  !
  address-family ipv4
    neighbor {PEER_IP} activate
    neighbor {PEER_IP} soft-reconfiguration inbound
    neighbor {PEER_IP} prefix-list PFX-IN-{PEER_NAME} in
    neighbor {PEER_IP} prefix-list PFX-OUT-{PEER_NAME} out
    neighbor {PEER_IP} maximum-prefix 100 80 warning-only
    network {LOCAL_PREFIX} mask {LOCAL_MASK}

cisco_ibgp_route_reflector.config:
router bgp {AS_NUMBER}
  bgp router-id {RR_LOOPBACK}
  bgp cluster-id {CLUSTER_ID}
  !
  neighbor IBGP-CLIENTS peer-group
  neighbor IBGP-CLIENTS remote-as {AS_NUMBER}
  neighbor IBGP-CLIENTS update-source Loopback0
  neighbor IBGP-CLIENTS route-reflector-client
  neighbor IBGP-CLIENTS password 7 {PASSWORD}
  !
  neighbor {CLIENT1_IP} peer-group IBGP-CLIENTS
  neighbor {CLIENT1_IP} description {CLIENT1_NAME}
  neighbor {CLIENT2_IP} peer-group IBGP-CLIENTS
  neighbor {CLIENT2_IP} description {CLIENT2_NAME}
  !
  address-family ipv4
    neighbor IBGP-CLIENTS activate
    neighbor IBGP-CLIENTS next-hop-self

ospf_summarization.config:
router ospf {PROCESS_ID}
  area {AREA_ID} range {SUMMARY_PREFIX} {SUMMARY_MASK}
  area {AREA_ID} range {SUMMARY_PREFIX2} {SUMMARY_MASK2} not-advertise  ! Suppress specific range

hsrp_v2.primary_config:
interface Vlan{VLAN_ID}
  description {VLAN_DESCRIPTION}
  ip address {PRIMARY_SVI_IP} {MASK}
  standby version 2
  standby {GROUP} ip {VIRTUAL_IP}
  standby {GROUP} priority 150
  standby {GROUP} preempt delay minimum 60 reload 180
  standby {GROUP} authentication md5 key-string {KEY}
  standby {GROUP} track GigabitEthernet1/0/1 decrement 60
  standby {GROUP} track GigabitEthernet1/0/2 decrement 60
  no ip proxy-arp

hsrp_v2.secondary_config:
interface Vlan{VLAN_ID}
  ip address {SECONDARY_SVI_IP} {MASK}
  standby version 2
  standby {GROUP} ip {VIRTUAL_IP}
  standby {GROUP} priority 100
  standby {GROUP} preempt delay minimum 60
  standby {GROUP} authentication md5 key-string {KEY}

vrrp_v3.config:
interface Vlan{VLAN_ID}
  ip address {IP} {MASK}
  vrrp {GROUP} address-family ipv4
    address {VIRTUAL_IP} primary
    priority {PRIORITY}
    preempt
    timers advertise 1000  ! 1 second in milliseconds
    track object UPLINK decrement 50

glbp.config:
interface Vlan{VLAN_ID}
  ip address {IP} {MASK}
  glbp {GROUP} ip {VIRTUAL_IP}
  glbp {GROUP} priority 150
  glbp {GROUP} preempt
  glbp {GROUP} load-balancing round-robin  ! or: host-dependent, weighted

pci_dss_cde_acl.vlan_application:
interface Vlan{CDE_VLAN}
  ip access-group PERMIT-TO-CDE in
  ip access-group PERMIT-FROM-CDE out
